import{_ as o,o as r,c as t,ai as s}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"消息顺序性保障机制","description":"","frontmatter":{},"headers":[],"relativePath":"mq/message-order.md","filePath":"mq/message-order.md"}'),n={name:"mq/message-order.md"};function a(g,e,l,i,d,c){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="消息顺序性保障机制" tabindex="-1">消息顺序性保障机制 <a class="header-anchor" href="#消息顺序性保障机制" aria-label="Permalink to “消息顺序性保障机制”">​</a></h1><hr><h3 id="❓-面试官-如果我发送了-创建订单-、-订单付款-、-订单发货-三条消息-怎么保证消费者一定能按这个顺序去执行" tabindex="-1">❓ 面试官：如果我发送了“创建订单”、“订单付款”、“订单发货”三条消息，怎么保证消费者一定能按这个顺序去执行？ <a class="header-anchor" href="#❓-面试官-如果我发送了-创建订单-、-订单付款-、-订单发货-三条消息-怎么保证消费者一定能按这个顺序去执行" aria-label="Permalink to “❓ 面试官：如果我发送了“创建订单”、“订单付款”、“订单发货”三条消息，怎么保证消费者一定能按这个顺序去执行？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 普通的 MQ 为了提高并发吞吐量，默认都是<strong>多队列多线程并发消费</strong>的，绝对无法保证全局顺序！ 要想保证顺序，必须满足两个核心条件：<strong>1. 生产者把属于同一个业务（如同一个订单）的消息发送到同一个队列（Queue/Partition）里；2. 消费者针对这个队列，必须使用单线程串行消费</strong>。这被称为<strong>“局部顺序性”</strong>。</p><p><strong>📝 详细原理解析与常见破坏顺序的坑：</strong></p><h4 id="为什么普通模式下会乱序" tabindex="-1">为什么普通模式下会乱序？ <a class="header-anchor" href="#为什么普通模式下会乱序" aria-label="Permalink to “为什么普通模式下会乱序？”">​</a></h4><ul><li><strong>发送端乱序</strong>：生产者开启了多个线程并发发消息，或者网络有延迟。虽然发出了 <code>创建(1)</code>、<code>付款(2)</code>、<code>发货(3)</code>，但到达 MQ 服务端的顺序可能变成了 <code>1 -&gt; 3 -&gt; 2</code>。</li><li><strong>MQ 存储乱序</strong>：比如 RocketMQ 默认有 4 个队列（Queue）。轮询策略下，<code>创建</code>进了 Queue1，<code>付款</code>进了 Queue2。</li><li><strong>消费端乱序（最常见）</strong>：消费者拉到了 <code>1、2、3</code> 这三条消息，交给了内部的<strong>线程池</strong>去并发处理。处理 <code>发货</code> 的线程跑得快，一下子就处理完了；处理 <code>创建订单</code> 的线程因为卡在写数据库，还没结束。导致业务逻辑变成了“先发货，再创建订单”，直接引发极其严重的数据脏乱报错。</li></ul><hr><h3 id="❓-面试官-那具体到代码层面-在-rocketmq-里怎么实现局部顺序消费-【中高级】" tabindex="-1">❓ 面试官：那具体到代码层面，在 RocketMQ 里怎么实现局部顺序消费？【中高级】 <a class="header-anchor" href="#❓-面试官-那具体到代码层面-在-rocketmq-里怎么实现局部顺序消费-【中高级】" aria-label="Permalink to “❓ 面试官：那具体到代码层面，在 RocketMQ 里怎么实现局部顺序消费？【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong></p><ul><li>生产者端：自定义个 <code>MessageQueueSelector</code>（队列选择器），把<strong>同一个订单号进行 Hash 取模</strong>，确保这笔订单的 3 条消息永远被路由到固定的那 <strong>1 个 Queue</strong> 里。</li><li>消费者端：不能使用普通的并发监听器，必须注册专门的 <strong><code>MessageListenerOrderly</code>（顺序监听器）</strong>。</li></ul><p><strong>📝 RocketMQ 的顺序消费黑科技：</strong> 很多人会觉得：“既然只能放到一个 Queue 里，还强制我单线程消费，那我整个系统的吞吐量岂不是崩盘了？” 其实并没有那么糟，RocketMQ 在底层做了非常巧妙的设计：</p><ol><li><strong>一把分布式锁（保证排他性）</strong>：当消费者启动时，它会去向 MQ 的 Broker 申请一把<strong>针对某个 Queue 的分布式锁</strong>。只要拿到了锁，别的消费节点绝对不能碰这个 Queue 里的消息。</li><li><strong>细粒度的单线程</strong>：它并不是强迫你整个消费者 JVM 只用一个线程干活！它是<strong>对每个 Queue 分配一个独立的线程</strong>去串行处理。如果你有 16 个 Queue，那你的应用里同时就会有 16 个线程在并发干活，只不过具体到 <code>Queue1</code> 内部，它的消息绝对是串行一个一个往下走的。</li></ol><hr><h3 id="❓-面试官-如果顺序消费的过程中-第二条消息一直消费失败-报错抛异常-怎么办-会阻塞后面的消息吗-【高级】" tabindex="-1">❓ 面试官：如果顺序消费的过程中，第二条消息一直消费失败（报错抛异常）怎么办？会阻塞后面的消息吗？【高级】 <a class="header-anchor" href="#❓-面试官-如果顺序消费的过程中-第二条消息一直消费失败-报错抛异常-怎么办-会阻塞后面的消息吗-【高级】" aria-label="Permalink to “❓ 面试官：如果顺序消费的过程中，第二条消息一直消费失败（报错抛异常）怎么办？会阻塞后面的消息吗？【高级】”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong><strong>一定会阻塞！这是顺序消费最大的致命伤</strong>。因为你要保证绝对顺序，在“订单付款（第2条）”没消费成功之前，MQ 绝对不敢把“订单发货（第3条）”交给你，否则顺序就乱了。它会无限重试消费第 2 条消息，导致这个 Queue 里后面的所有消息发生<strong>极其严重的积压</strong>。</p><p><strong>📝 真实生产环境的破局之道（面试高分答题点）：</strong></p><p>&quot;面试官您好，在我们真实的业务中，其实<strong>极少、极少去使用 MQ 的强顺序消费机制</strong>，因为它的阻塞代价太大，可用性太差。我们通常会通过<strong>『业务状态机』</strong>在代码层面来变相解决乱序问题！&quot;</p><p><strong>我们的改造方案（状态机设计模式）：</strong></p><ol><li>放弃强顺序队列，依然用普通的高并发队列发这 3 条消息，提升 10 倍吞吐量。</li><li>在数据库的订单表里加上严格的<strong>状态字段</strong>：<code>1-已创建，2-已付款，3-已发货</code>。</li><li>当消费者乱序拿到了<strong>“订单发货(3)”</strong>的消息时，它去查一下数据库，发现当前订单状态是<strong>空</strong>或者<strong>“已创建(1)”</strong>。</li><li><strong>核心逻辑</strong>：代码判断当前状态不满足发货条件（缺乏中间的已付款状态），不报错，直接手动把这条消息<strong>扔回 MQ 稍后再重试</strong>（延时消费），或者先暂存到 Redis 里。</li><li>等一会儿“订单付款(2)”的消息被处理完，订单状态变成了 2。这时候暂存的那条“发货消息”再来检查一遍，发现条件满足了，顺利放行执行。</li></ol><p><strong>总结</strong>：通过在消费者代码里增加<strong>依赖状态判断</strong>的前置逻辑，哪怕消息是乱着来的，我们也能在业务代码里把它“理顺”，这比死磕 MQ 的顺序队列要健壮得多。</p>',24)])])}const h=o(n,[["render",a]]);export{p as __pageData,h as default};
